51	/// `application/json; charset=utf-8`.
52	pub const CT_JSON: &str = "application/json; charset=utf-8";
53	/// `text/html; charset=utf-8`.
54	pub const CT_HTML: &str = "text/html; charset=utf-8";
55	/// `text/plain; charset=utf-8` (text bodies, `next`/`prev`, DOT, `robots`, `kill`).
56	pub const CT_TEXT: &str = "text/plain; charset=utf-8";
57	/// `application/octet-stream` (the `download` route).
58	pub const CT_OCTET: &str = "application/octet-stream";
