60	/// `Cache-Control` value on `303` redirects (and the favicon redirect).
61	pub const CACHE_CONTROL_NOCACHE: &str = "no-cache, must-revalidate";
62	/// `Expires` value paired with [`CACHE_CONTROL_NOCACHE`] (a fixed past instant).
63	pub const EXPIRES_PAST: &str = "Thu, 01 Jan 1970 05:05:05 GMT";
