65	/// HTTP request method (only the two the UI uses are modelled).
66	#[derive(Debug, PartialEq, Eq, Clone, Copy)]
67	pub enum HttpMethod {
68	    Get,
69	    Post,
70	}
71	
72	impl HttpMethod {
73	    fn as_str(self) -> &'static str {
74	        match self {
75	            HttpMethod::Get => "GET",
76	            HttpMethod::Post => "POST",
77	        }
78	    }
79	}
80	
81	/// An incoming request. `path` is the URL path with any `?query` split off into
82	/// `query` (decoded key/value pairs).
83	pub struct Request<'a> {
84	    pub method: HttpMethod,
85	    pub path: &'a str,
86	    /// Decoded query-string pairs (e.g. `("path", "solve(...)")` for `/kill`).
87	    pub query: &'a [(String, String)],
88	    /// Decoded POST form fields (e.g. `("lemma-text", "lemma foo: …")`, or
89	    /// `("uploadedTheory", <source>)` for an upload).
90	    pub form: &'a [(String, String)],
91	}
92	
93	impl<'a> Request<'a> {
94	    pub fn get(path: &'a str) -> Request<'a> {
95	        Request { method: HttpMethod::Get, path, query: &[], form: &[] }
96	    }
97	    pub fn get_query(path: &'a str, query: &'a [(String, String)]) -> Request<'a> {
98	        Request { method: HttpMethod::Get, path, query, form: &[] }
99	    }
100	    pub fn post(path: &'a str, form: &'a [(String, String)]) -> Request<'a> {
101	        Request { method: HttpMethod::Post, path, query: &[], form }
102	    }
103	    fn field(&self, key: &str) -> &str {
104	        Self::lookup(self.form, key)
105	    }
106	    fn query_param(&self, key: &str) -> Option<&str> {
107	        self.query.iter().find(|(k, _)| k == key).map(|(_, v)| v.as_str())
108	    }
109	    fn lookup<'b>(pairs: &'b [(String, String)], key: &str) -> &'b str {
110	        pairs.iter().find(|(k, _)| k == key).map(|(_, v)| v.as_str()).unwrap_or("")
111	    }
112	}
113	
114	/// An outgoing response. `location` is set for `3xx` redirects; `no_cache`
115	/// requests the `Cache-Control`/`Expires` pair Yesod attaches to redirects.
116	#[derive(Debug, PartialEq, Eq, Clone)]
117	pub struct Response {
118	    pub status: u16,
119	    pub content_type: &'static str,
120	    pub body: String,
121	    pub location: Option<String>,
122	    pub no_cache: bool,
123	}
124	
125	impl Response {
126	    fn base(status: u16, content_type: &'static str, body: String) -> Response {
127	        Response { status, content_type, body, location: None, no_cache: false }
128	    }
129	    fn json(body: String) -> Response {
130	        Response::base(200, CT_JSON, body)
131	    }
132	    fn html(body: String) -> Response {
133	        Response::base(200, CT_HTML, body)
134	    }
135	    fn text(body: String) -> Response {
136	        Response::base(200, CT_TEXT, body)
137	    }
138	    fn octet(body: String) -> Response {
139	        Response::base(200, CT_OCTET, body)
140	    }
141	    fn see_other(location: String) -> Response {
142	        Response { status: 303, content_type: CT_TEXT, body: String::new(), location: Some(location), no_cache: true }
143	    }
144	    fn not_found(echoed_path: &str) -> Response {
145	        Response::base(404, CT_HTML, errors::render_not_found(echoed_path))
146	    }
147	    fn invalid_args(messages: &[&str]) -> Response {
148	        Response::base(400, CT_HTML, errors::render_invalid_args(messages))
149	    }
150	    fn bad_method(method: HttpMethod) -> Response {
151	        Response::base(405, CT_HTML, errors::render_bad_method(method.as_str()))
152	    }
153	    /// The static-handler `404` for a missing file (plain text, distinct from the
154	    /// full-HTML `404` of the dynamic router).
155	    fn static_missing() -> Response {
156	        Response::base(404, CT_TEXT, assets::STATIC_NOT_FOUND.to_string())
157	    }
158	}
