187	/// A request for a `main/*` content pane, resolved to the prover.
188	pub enum MainReq<'a> {
189	    Help,
190	    Message,
191	    Rules,
192	    Tactic,
193	    Cases { refined: bool, level: usize, n: usize },
194	    Lemma(&'a str),
195	    Proof { lemma: &'a str, path: &'a [String] },
