202	/// The prover-supplied callbacks. The web layer treats every returned string as an
203	/// opaque fragment; the *decisions* around these calls (version allocation, route
204	/// dispatch, envelope shape, content types, redirects) live in [`Server`].
205	pub trait ProverOps {
206	    /// Opaque per-version theory handle held by the [`Server`].
207	    type Theory;
208	
209	    // ---- pretty-printers / fragment producers ----
210	    /// Shell metadata (theory name, Tamarin version string, source filename, and
211	    /// the load [`Origin`]). The prover is the authority on a version's origin: a
212	    /// proof-derived version reports the same origin as the base it came from.
213	    fn meta(&self, thy: &Self::Theory) -> Meta;
214	    /// Index-page row data (load time, origin, modified flag) for `thy`.
215	    fn root_meta(&self, thy: &Self::Theory) -> RootMeta;
216	    /// The `source`/`message`/`download` body: the theory source, verbatim.
217	    fn source_text(&self, thy: &Self::Theory) -> String;
218	    /// Inner HTML of the west proof-script pane at `index`.
219	    fn west_pane(&self, thy: &Self::Theory, index: u64) -> String;
220	    /// Center-pane content (html + title) for a `main/*` view at `index`.
221	    fn main_content(&self, thy: &Self::Theory, index: u64, req: &MainReq) -> Content;
222	    /// Raw (unescaped) current source of a lemma, for the edit form.
223	    fn lemma_source(&self, thy: &Self::Theory, name: &str) -> Option<String>;
224	    /// Graphviz DOT for an `interactive-graph-def` node.
225	    fn graph_dot(&self, thy: &Self::Theory, tail: &[String]) -> String;
226	    /// The `next`/`prev` target URL (bare path), from the prover's traversal.
227	    fn nav_target(&self, thy: &Self::Theory, index: u64, dir: NavDir, mode: &str, lemma: &str) -> String;
228	    /// The `get_and_append` alert message (names the file appended to).
229	    fn append_message(&self, thy: &Self::Theory) -> String;
230	    /// Raw bytes of a `/static/<path>` asset, or `None` if the file is absent.
231	    fn static_file(&self, path: &[String]) -> Option<Vec<u8>>;
232	
233	    // ---- mutations / loads ----
234	    /// Parse an uploaded theory source into a theory, or `None` on failure.
235	    fn load_theory(&self, source: &str) -> Option<Self::Theory>;
236	    /// Re-read the theory from its source in place (the `reload` route).
237	    fn reload(&self, thy: &Self::Theory) -> Self::Theory;
238	    /// Apply proof method `n` at `(lemma, path)`. `Some((theory, focus))` on
239	    /// success (`focus` = the prover's next open goal, incl. root `_`); `None`
240	    /// if the method application failed (the web layer answers a JSON alert).
241	    fn apply_method(&self, thy: &Self::Theory, lemma: &str, n: usize, path: &[String]) -> Option<(Self::Theory, Vec<String>)>;
242	    /// Autoprove per `spec`. Returns the new theory and resulting focus path.
243	    fn autoprove(&self, thy: &Self::Theory, spec: &Autoprove) -> (Self::Theory, Vec<String>);
244	    /// Edit lemma `name` in place. `Some` = the modified theory; `None` = parse/wf
245	    /// failure or unknown lemma (the web layer then re-renders the edit form).
246	    fn edit_lemma(&self, thy: &Self::Theory, name: &str, text: &str) -> Option<Self::Theory>;
247	    /// Add a lemma at position `pos`. `Some`/`None` as for [`Self::edit_lemma`].
248	    fn add_lemma(&self, thy: &Self::Theory, pos: &str, text: &str) -> Option<Self::Theory>;
249	    /// Delete lemma `name` in place. `Some` = the modified theory (redirect to the
250	    /// help view); `None` = lemma not found (redirect to the delete view).
251	    fn delete_lemma(&self, thy: &Self::Theory, name: &str) -> Option<Self::Theory>;
252	
253	    // ---- del/path + verify (theory-path operations) ----
254	    /// Whether `lemma` is a lemma present in `thy`. Drives the `verify/proof/…`
255	    /// redirect-vs-content choice: a `verify/proof/{lemma}[/path]` redirects to the
256	    /// proof view iff the lemma is present, otherwise the help pane is returned.
257	    fn lemma_present(&self, thy: &Self::Theory, lemma: &str) -> bool;
258	    /// Delete the proof at the lemma node `name` (`del/path/lemma/{name}`),
259	    /// producing a fresh theory version. `None` if the lemma cannot be removed
260	    /// (absent) — the web layer then answers a "removing the selected lemma failed"
261	    /// alert.
262	    fn del_lemma_path(&self, thy: &Self::Theory, name: &str) -> Option<Self::Theory>;
263	    /// Remove the proof step at a proof node (`del/path/proof/…`, or the diff
264	    /// `del/path/diffProof/…` when `diff`), producing a fresh theory version.
265	    /// `None` if the node cannot be removed (nonexistent lemma or unremovable node)
266	    /// — the web layer then answers a "removing the selected proof step failed"
267	    /// alert.
268	    fn del_proof_step(&self, thy: &Self::Theory, lemma: &str, path: &[String], diff: bool) -> Option<Self::Theory>;
269	
270	    // ---- diff-mode (observational equivalence) ----
271	    /// Apply a diff proof method; `Some`/`None` as for [`Self::apply_method`].
272	    fn apply_diff_method(&self, thy: &Self::Theory, lemma: &str, n: usize, path: &[String]) -> Option<(Self::Theory, Vec<String>)>;
273	    /// Autoprove a single diff lemma per `spec`; returns theory + focus path.
274	    fn autoprove_diff(&self, thy: &Self::Theory, spec: &AutoproveDiff) -> (Self::Theory, Vec<String>);
275	    /// Autoprove all lemmas per `spec`; returns the resulting theory.
276	    fn autoprove_all(&self, thy: &Self::Theory, spec: &AutoproveAll) -> Self::Theory;
277	}
