279	/// The theory-version **state backend**: the single owner of the version set and
280	/// the monotonic version counter. [`Server`] holds no version map of its own and
281	/// drives all version state exclusively through this trait, so a consumer can
282	/// supply an asynchronous, internally-caching backend that remains the sole owner
283	/// of theory state ([`InMemoryState`] is the reference in-memory implementation).
284	///
285	/// The lifecycle semantics below are the **contract** a backend must satisfy for
286	/// the observed web-UI behaviour to hold (probed live; `BEHAVIOR.md` §§13.1/14.3,
287	/// §16). One global index namespace covers every loaded, uploaded, or
288	/// proof-derived version:
289	///
290	/// * **Monotonic allocation.** [`insert_new`](StateOps::insert_new) stores the
291	///   theory at `= (max index ever allocated) + 1`, never reusing an index and
292	///   independent of any base index. The first allocation on a fresh backend is
293	///   index `1` (the originally loaded theory).
294	/// * **Retention.** Every allocated index stays resolvable by
295	///   [`get`](StateOps::get) for the backend's lifetime; the web layer never asks
296	///   for a version to be dropped (the index-page window is a display cap only).
297	/// * **In-place mutation.** [`replace`](StateOps::replace) overwrites the theory
298	///   at an existing index (structural edits + `reload`) without allocating, and
299	///   leaves the counter and every other version untouched. The web layer only
300	///   calls it on an index it has already resolved.
301	/// * **Enumeration.** [`entries`](StateOps::entries) yields all `(index, theory)`
302	///   in ascending index order (drives the index page).
303	/// * **Deletion.** [`remove`](StateOps::remove) drops a version. Under the observed
304	///   retention contract the web layer never invokes it; it is part of the
305	///   backend's ownership surface (e.g. cache eviction) — see the honesty note in
306	///   `REPORT.md`.
307	pub trait StateOps {
308	    /// The per-version theory handle, shared with [`ProverOps::Theory`].
309	    type Theory;
310	    /// Allocate a fresh monotonic index, store `theory` there, and return the
311	    /// index (never reused; `1` on a fresh backend). Prior versions are retained.
312	    fn insert_new(&mut self, theory: Self::Theory) -> u64;
313	    /// Retrieve the theory at `index`, or `None` if no such version exists.
314	    fn get(&self, index: u64) -> Option<&Self::Theory>;
315	    /// Overwrite the theory at an existing `index` in place (no allocation; the
316	    /// counter and other versions are untouched).
317	    fn replace(&mut self, index: u64, theory: Self::Theory);
318	    /// Remove the version at `index` (returning it if present). Not exercised by
319	    /// the current web-layer surface — see the trait-level note.
320	    fn remove(&mut self, index: u64) -> Option<Self::Theory>;
321	    /// All `(index, theory)` pairs in ascending index order.
322	    fn entries(&self) -> Vec<(u64, &Self::Theory)>;
323	}
324	
325	/// In-memory reference implementation of [`StateOps`]: a `BTreeMap` keyed by index
326	/// plus a monotonic counter. Satisfies the full lifecycle contract and is the
327	/// default backend used by [`Server::new`].
328	pub struct InMemoryState<T> {
329	    versions: BTreeMap<u64, T>,
330	    next_index: u64,
331	}
332	
333	impl<T> InMemoryState<T> {
334	    /// An empty backend whose first [`StateOps::insert_new`] allocates index `1`.
335	    pub fn new() -> InMemoryState<T> {
336	        InMemoryState { versions: BTreeMap::new(), next_index: 1 }
337	    }
338	
339	    /// A backend pre-seeded with `base` at index `1` (the originally loaded
340	    /// theory).
341	    pub fn seeded(base: T) -> InMemoryState<T> {
342	        let mut s = InMemoryState::new();
343	        let i = s.insert_new(base);
344	        debug_assert_eq!(i, 1, "the first allocated version index is 1");
345	        s
346	    }
347	}
348	
349	impl<T> Default for InMemoryState<T> {
350	    fn default() -> Self {
351	        InMemoryState::new()
352	    }
353	}
354	
355	impl<T> StateOps for InMemoryState<T> {
356	    type Theory = T;
357	
358	    fn insert_new(&mut self, theory: T) -> u64 {
359	        let index = self.next_index;
360	        self.next_index += 1;
361	        self.versions.insert(index, theory);
362	        index
363	    }
364	    fn get(&self, index: u64) -> Option<&T> {
365	        self.versions.get(&index)
366	    }
367	    fn replace(&mut self, index: u64, theory: T) {
368	        self.versions.insert(index, theory);
369	    }
370	    fn remove(&mut self, index: u64) -> Option<T> {
371	        self.versions.remove(&index)
372	    }
373	    fn entries(&self) -> Vec<(u64, &T)> {
374	        self.versions.iter().map(|(&i, t)| (i, t)).collect()
375	    }
376	}
377	
378	/// The interactive server. It owns all route dispatch, transport, and response
379	/// assembly, but **not** the version state: that lives behind a [`StateOps`]
380	/// backend `S` (defaulting to the in-memory [`InMemoryState`]). Every version
381	/// read/allocation/mutation flows through `S`.
382	pub struct Server<P: ProverOps, S: StateOps<Theory = P::Theory> = InMemoryState<<P as ProverOps>::Theory>> {
383	    ops: P,
384	    state: S,
385	}
386	
387	impl<P: ProverOps> Server<P, InMemoryState<P::Theory>> {
388	    /// Create a server holding `base` as version 1 in a fresh in-memory backend.
389	    pub fn new(ops: P, base: P::Theory) -> Server<P, InMemoryState<P::Theory>> {
390	        Server::with_state(ops, InMemoryState::seeded(base))
391	    }
392	}
393	
394	impl<P: ProverOps, S: StateOps<Theory = P::Theory>> Server<P, S> {
395	    /// Create a server over a caller-supplied state backend. The backend must
396	    /// already hold the base theory at index 1 (see the [`StateOps`] contract);
397	    /// this is the seam a consumer uses to plug in its own theory-state owner.
398	    pub fn with_state(ops: P, state: S) -> Server<P, S> {
399	        Server { ops, state }
400	    }
401	
402	    /// Version indices currently allocated (ascending). All are resolvable.
403	    pub fn versions(&self) -> Vec<u64> {
404	        self.state.entries().into_iter().map(|(i, _)| i).collect()
405	    }
406	
407	    /// The theory at a **resolved** index (panics if absent — callers resolve
408	    /// first via [`Self::resolve`]).
409	    fn theory(&self, index: u64) -> &P::Theory {
410	        self.state.get(index).expect("dispatch resolves the index before use")
411	    }
412	
413	    fn resolve(&self, index: &Index) -> Option<u64> {
414	        match index {
415	            Index::Num(v) if self.state.get(*v).is_some() => Some(*v),
416	            _ => None,
417	        }
418	    }
419	
420	    fn commit_new_version(&mut self, thy: P::Theory) -> u64 {
421	        self.state.insert_new(thy)
422	    }
423	
424	    /// Dispatch a request across the whole surface, mutating version state as
425	    /// observed.
426	    pub fn dispatch(&mut self, req: &Request) -> Response {
427	        match Toplevel::parse(req.path) {
428	            Toplevel::Root => self.root(req),
429	            Toplevel::Robots => self.get_only(req, || Response::text(assets::ROBOTS_TXT.to_string())),
430	            Toplevel::Favicon => self.get_only(req, || Response::see_other(assets::FAVICON_TARGET.to_string())),
431	            Toplevel::Kill => self.kill(req),
432	            Toplevel::Static(segs) => self.static_asset(req, &segs),
433	            Toplevel::Thy(route) => self.thy(req, &route),
434	            Toplevel::Other(_) => Response::not_found(req.path),
435	        }
436	    }
437	
438	    /// Run `f` for a GET; a non-GET on a GET-only route answers `405`.
439	    fn get_only(&self, req: &Request, f: impl FnOnce() -> Response) -> Response {
440	        match req.method {
441	            HttpMethod::Get => f(),
442	            other => Response::bad_method(other),
443	        }
444	    }
445	
446	    // ---- top-level routes ------------------------------------------------
447	
448	    fn root(&mut self, req: &Request) -> Response {
449	        match req.method {
450	            HttpMethod::Get => Response::html(self.render_index(Flash::None)),
451	            HttpMethod::Post => {
452	                let uploaded = req.field("uploadedTheory");
453	                let loaded = if uploaded.is_empty() {
454	                    None
455	                } else {
456	                    self.ops.load_theory(uploaded)
457	                };
458	                match loaded {
459	                    Some(thy) => {
460	                        self.commit_new_version(thy);
461	                        Response::html(self.render_index(Flash::Loaded))
462	                    }
463	                    None => Response::html(self.render_index(Flash::PostFailed)),
464	                }
465	            }
466	        }
467	    }
468	
469	    /// Render the index page for the current version set. Rows are emitted in
470	    /// ascending index order; the reference server's exact row *ordering* and the
471	    /// per-row time/origin are non-deterministic (prover/environment concerns).
472	    fn render_index(&self, flash: Flash) -> String {
473	        let entries = self.state.entries();
474	        let mut version = String::new();
475	        let mut rows: Vec<RootRow> = Vec::with_capacity(entries.len());
476	        // Owned strings must outlive the borrowed RootRow slice.
477	        let mut owned: Vec<(u64, String, String, bool, String)> = Vec::new();
478	        for (idx, thy) in entries {
479	            let m = self.ops.meta(thy);
480	            let rm = self.ops.root_meta(thy);
481	            if version.is_empty() {
482	                version = m.version.clone();
483	            }
484	            owned.push((idx, m.name, rm.time, rm.modified, rm.origin));
485	        }
486	        for (idx, name, time, modified, origin) in &owned {
487	            rows.push(RootRow { index: *idx, name, time, modified: *modified, origin });
488	        }
489	        page::render_root(flash, &version, &rows)
490	    }
