520	    fn thy(&mut self, req: &Request, route: &Route) -> Response {
521	        let index = match self.resolve(&route.index) {
522	            Some(v) => v,
523	            None => return Response::not_found(req.path),
524	        };
525	        let kind = shell_kind(&route.theory_kind);
526	        match (req.method, &route.handler) {
527	            // Proof operations (allocate a new version) — intercept before reads.
528	            (HttpMethod::Get, Handler::Main(Main::Method { lemma, n, path })) => {
529	                self.proof_method(kind, index, &lemma.clone(), *n, &path.clone(), false)
530	            }
531	            (HttpMethod::Get, Handler::Main(Main::DiffMethod { lemma, n, path })) => {
532	                self.proof_method(kind, index, &lemma.clone(), *n, &path.clone(), true)
533	            }
534	            (HttpMethod::Get, Handler::Main(m)) => self.get_main(index, m),
535	            (HttpMethod::Get, Handler::Overview(tail)) => {
536	                self.get_overview(kind, index, &OverviewView::parse(tail))
537	            }
538	            (HttpMethod::Get, Handler::Autoprove(tail)) => match Autoprove::parse(tail) {
539	                Some(ap) => {
540	                    let (thy, focus) = self.ops.autoprove(self.theory(index), &ap);
541	                    let new = self.commit_new_version(thy);
542	                    Response::json(envelope::render_redirect(&overview_proof_path(kind, new, &ap.lemma, &focus, false)))
543	                }
544	                None => Response::not_found(req.path),
545	            },
546	            (HttpMethod::Get, Handler::AutoproveDiff(tail)) => match AutoproveDiff::parse(tail) {
547	                Some(ap) => {
548	                    let (thy, focus) = self.ops.autoprove_diff(self.theory(index), &ap);
549	                    let new = self.commit_new_version(thy);
550	                    Response::json(envelope::render_redirect(&overview_proof_path(kind, new, &ap.lemma, &focus, true)))
551	                }
552	                None => Response::not_found(req.path),
553	            },
554	            (HttpMethod::Get, Handler::AutoproveAll(tail)) => match AutoproveAll::parse(tail) {
555	                Some(ap) => {
556	                    let thy = self.ops.autoprove_all(self.theory(index), &ap);
557	                    let new = self.commit_new_version(thy);
558	                    Response::json(envelope::render_redirect(&format!("/thy/{}/{}/overview/help", kind.path(), new)))
559	                }
560	                None => Response::not_found(req.path),
561	            },
562	            (HttpMethod::Get, Handler::Next(tail)) => self.get_nav(index, NavDir::Next, tail, req.path),
563	            (HttpMethod::Get, Handler::Prev(tail)) => self.get_nav(index, NavDir::Prev, tail, req.path),
564	            (HttpMethod::Get, Handler::Source) | (HttpMethod::Get, Handler::Message) => {
565	                Response::text(self.ops.source_text(self.theory(index)))
566	            }
567	            (HttpMethod::Get, Handler::Download(_)) => {
568	                Response::octet(self.ops.source_text(self.theory(index)))
569	            }
570	            (HttpMethod::Get, Handler::Intdot(tail)) => self.get_intdot(kind, index, tail),
571	            (HttpMethod::Get, Handler::InteractiveGraphDef(tail)) => {
572	                Response::text(self.ops.graph_dot(self.theory(index), tail))
573	            }
574	            // Wrong method on GET-only theory routes.
575	            (HttpMethod::Post, Handler::Source)
576	            | (HttpMethod::Post, Handler::Message)
577	            | (HttpMethod::Post, Handler::Download(_)) => Response::bad_method(HttpMethod::Post),
578	
579	            // In-place mutating POSTs.
580	            (HttpMethod::Post, Handler::Reload) => {
581	                let new_thy = self.ops.reload(self.theory(index));
582	                self.state.replace(index, new_thy);
583	                Response::json(envelope::render_redirect(&format!("/thy/{}/{}/overview/help", kind.path(), index)))
584	            }
585	            (HttpMethod::Get, Handler::Reload) => Response::bad_method(HttpMethod::Get),
586	            (HttpMethod::Post, Handler::GetAndAppend(_)) => {
587	                Response::json(envelope::render_alert(&self.ops.append_message(self.theory(index))))
588	            }
589	            (HttpMethod::Get, Handler::GetAndAppend(_)) => Response::bad_method(HttpMethod::Get),
590	            (HttpMethod::Post, Handler::Edit(tail)) => self.post_edit(kind, index, tail, req),
591	
592	            // del/path (both kinds) and verify (trace only). The theory-path parse
593	            // decides route-match (unparseable -> 404 for any method); a parseable
594	            // path with a non-GET method is a 405.
595	            (_, Handler::DelPath(segs)) => self.del_path(req.method, kind, index, segs, req.path),
596	            (_, Handler::Verify(segs)) => {
597	                if kind == ShellKind::Trace {
598	                    self.verify(req.method, index, segs, req.path)
599	                } else {
600	                    // `verify` is not registered for equiv theories: a miss for any method.
601	                    Response::not_found(req.path)
602	                }
603	            }
604	            _ => Response::not_found(req.path),
605	        }
606	    }
