710	    // ---- del/path : delete a theory path (proof op — new version) ----
711	    /// Dispatch a `del/path/…` request. The theory-path tail parses mode-aware
712	    /// (`kind`); an unparseable tail is a `404` (for any method), a parseable tail
713	    /// with a non-GET method is a `405`. A deletable path (a lemma or proof node)
714	    /// allocates a fresh version and redirects to `overview/<same-path>`; every
715	    /// other outcome is a JSON alert whose text is selected by the path type.
716	    fn del_path(&mut self, method: HttpMethod, kind: ShellKind, index: u64, segs: &[String], path: &str) -> Response {
717	        let diff = kind == ShellKind::Equiv;
718	        let thy_path = match ThyPath::parse(segs, diff) {
719	            Some(tp) => tp,
720	            None => return Response::not_found(path),
721	        };
722	        if method != HttpMethod::Get {
723	            return Response::bad_method(method);
724	        }
725	        match thy_path {
726	            ThyPath::Lemma(name) => match self.ops.del_lemma_path(self.theory(index), &name) {
727	                Some(new_thy) => {
728	                    let new = self.commit_new_version(new_thy);
729	                    Response::json(envelope::render_redirect(&overview_lemma_path(kind, new, &name)))
730	                }
731	                None => Response::json(envelope::render_alert(envelope::DEL_LEMMA_FAILED_ALERT)),
732	            },
733	            ThyPath::Proof { lemma, path } => self.del_proof(kind, index, &lemma, &path, false),
734	            ThyPath::DiffProof { lemma, path } => self.del_proof(kind, index, &lemma, &path, true),
735	            ThyPath::Other => Response::json(envelope::render_alert(envelope::DEL_PATH_CANT_ALERT)),
736	        }
737	    }
