739	    fn del_proof(&mut self, kind: ShellKind, index: u64, lemma: &str, path: &[String], diff: bool) -> Response {
740	        match self.ops.del_proof_step(self.theory(index), lemma, path, diff) {
741	            Some(new_thy) => {
742	                let new = self.commit_new_version(new_thy);
743	                Response::json(envelope::render_redirect(&overview_proof_path(kind, new, lemma, path, diff)))
744	            }
745	            None => Response::json(envelope::render_alert(envelope::DEL_PROOF_STEP_FAILED_ALERT)),
746	        }
747	    }
