749	    // ---- verify : re-render a theory path (trace only; never mutates) ----
750	    /// Dispatch a `verify/…` request (trace theories only — the caller answers a
751	    /// `404` in equiv mode). The theory-path tail parses in the trace grammar; an
752	    /// unparseable tail is a `404`, a parseable tail with a non-GET method a `405`.
753	    /// A `proof/{lemma}[/path]` whose lemma is present redirects to
754	    /// `overview/proof/{lemma}[/path]` at the **same** version; every other path
755	    /// (including a proof path to an absent lemma) returns the theory help pane.
756	    fn verify(&self, method: HttpMethod, index: u64, segs: &[String], path: &str) -> Response {
757	        let thy_path = match ThyPath::parse(segs, false) {
758	            Some(tp) => tp,
759	            None => return Response::not_found(path),
760	        };
761	        if method != HttpMethod::Get {
762	            return Response::bad_method(method);
763	        }
764	        let thy = self.theory(index);
765	        match thy_path {
766	            ThyPath::Proof { lemma, path } if self.ops.lemma_present(thy, &lemma) => {
767	                Response::json(envelope::render_redirect(&overview_proof_path(
768	                    ShellKind::Trace, index, &lemma, &path, false,
769	                )))
770	            }
771	            _ => {
772	                let content = self.ops.main_content(thy, index, &MainReq::Help);
773	                Response::json(envelope::render_content(&content.html, &content.title))
774	            }
775	        }
776	    }
