778	    // ---- structural POST: mutate in place; 303 (or 200 form on edit/add failure) ----
779	    fn post_edit(&mut self, kind: ShellKind, index: u64, tail: &[String], req: &Request) -> Response {
780	        let (verb, name) = match tail {
781	            [v, n] => match EditVerb::parse(v) {
782	                Some(verb) => (verb, n.clone()),
783	                None => return Response::not_found(req.path),
784	            },
785	            _ => return Response::not_found(req.path),
786	        };
787	        let k = kind.path();
788	        match verb {
789	            EditVerb::Delete => match self.ops.delete_lemma(self.theory(index), &name) {
790	                Some(new_thy) => {
791	                    self.state.replace(index, new_thy);
792	                    Response::see_other(format!("/thy/{k}/{index}/overview/help"))
793	                }
794	                // Lemma not found: theory unchanged, redirect to the delete view.
795	                None => Response::see_other(format!("/thy/{k}/{index}/overview/delete/{name}")),
796	            },
797	            EditVerb::Edit => {
798	                let text = req.field("lemma-text");
799	                match self.ops.edit_lemma(self.theory(index), &name, text) {
800	                    Some(new_thy) => {
801	                        self.state.replace(index, new_thy);
802	                        Response::see_other(format!("/thy/{k}/{index}/overview/edit/{name}"))
803	                    }
804	                    None => self.get_overview(kind, index, &OverviewView::Edit(name)),
805	                }
806	            }
807	            EditVerb::Add => {
808	                let text = req.field("lemma-text");
809	                match self.ops.add_lemma(self.theory(index), &name, text) {
810	                    Some(new_thy) => {
811	                        self.state.replace(index, new_thy);
812	                        Response::see_other(format!("/thy/{k}/{index}/overview/add/{name}"))
813	                    }
814	                    None => self.get_overview(kind, index, &OverviewView::Add(name)),
815	                }
816	            }
817	        }
818	    }
