827	/// Map a URL theory-kind segment to a shell variant.
828	fn shell_kind(kind: &str) -> ShellKind {
829	    match kind {
830	        "equiv" => ShellKind::Equiv,
831	        _ => ShellKind::Trace,
832	    }
