841	/// Build the redirect target for a proof operation: an `overview/proof/…` URL for
842	/// trace, or `overview/diffProof/…` for diff, at version `index`.
843	fn overview_proof_path(kind: ShellKind, index: u64, lemma: &str, focus: &[String], diff: bool) -> String {
844	    let handler = if diff { "diffProof" } else { "proof" };
845	    let mut s = format!("/thy/{}/{}/overview/{}/{}", kind.path(), index, handler, lemma);
846	    for seg in focus {
847	        s.push('/');
848	        s.push_str(seg);
849	    }
850	    s
851	}
