1	//! Round-6 tests: the origin-aware page shell threaded through `Server`, and the
2	//! state-delegation redesign (`StateOps` / `InMemoryState`).
3	//!
4	//! * **Origin threading (ITEM 1).** A `FakeProver` whose theory carries an
5	//!   [`Origin`] and reports it from `meta`; the tests assert that a command-line
6	//!   (Local) theory's overview shell shows the "Reload file" / "Append modified
7	//!   lemmas" items while an uploaded (Upload) theory's shell shows neither, and
8	//!   that a proof-derived version inherits the base's origin (BEHAVIOR §16;
9	//!   QUERIES.log [R60]).
10	//! * **State delegation (ITEM 2).** The `Server` drives version state only through
11	//!   the `StateOps` trait; a custom backend (`CountingState`) records that every
12	//!   allocation/retrieval/mutation flows through it, and the `InMemoryState`
13	//!   reference implementation is checked against the documented lifecycle
14	//!   contract (monotonic allocation, retention, in-place replace, remove).
15	
16	use web_clean::dispatch::{
17	    Content, InMemoryState, MainReq, Meta, ProverOps, Request, RootMeta, Server, StateOps,
18	};
19	use web_clean::page::Origin;
20	use web_clean::route::{Autoprove, AutoproveAll, AutoproveDiff, NavDir};
21	
22	// ---------------------------------------------------------------------------
23	// A fake prover whose theory records its load origin (Local vs Upload).
24	// ---------------------------------------------------------------------------
25	
26	#[derive(Clone)]
27	struct Thy {
28	    name: String,
29	    origin: Origin,
30	    lemmas: Vec<String>,
31	}
32	
33	struct Fake;
34	
35	fn local_base() -> Thy {
36	    Thy { name: "Tutorial".into(), origin: Origin::Local, lemmas: vec!["secrecy".into()] }
37	}
38	
39	impl ProverOps for Fake {
40	    type Theory = Thy;
41	
42	    fn meta(&self, thy: &Thy) -> Meta {
43	        // The prover reports each version's origin; the web layer renders it.
44	        Meta {
45	            name: thy.name.clone(),
46	            version: "1.13.0".into(),
47	            filename: format!("{}.spthy", thy.name),
48	            origin: thy.origin,
49	        }
50	    }
51	    fn root_meta(&self, thy: &Thy) -> RootMeta {
52	        RootMeta { time: "00:00:00".into(), origin: format!("{}.spthy", thy.name), modified: false }
53	    }
54	    fn source_text(&self, thy: &Thy) -> String {
55	        format!("theory {} begin\nend", thy.name)
56	    }
57	    fn west_pane(&self, _thy: &Thy, index: u64) -> String {
58	        format!("WEST@{index}")
59	    }
60	    fn main_content(&self, _thy: &Thy, index: u64, _req: &MainReq) -> Content {
61	        Content { html: format!("<p>help@{index}</p>"), title: "Help".to_string() }
62	    }
63	    fn lemma_source(&self, _thy: &Thy, name: &str) -> Option<String> {
64	        Some(format!("lemma {name}: exists-trace \"T\""))
65	    }
66	    fn graph_dot(&self, _thy: &Thy, _tail: &[String]) -> String {
67	        web_clean::intdot::EMPTY_GRAPH_DOT.to_string()
68	    }
69	    fn nav_target(&self, _thy: &Thy, index: u64, _dir: NavDir, _mode: &str, lemma: &str) -> String {
70	        format!("/thy/trace/{index}/main/proof/{lemma}")
71	    }
72	    fn append_message(&self, _thy: &Thy) -> String {
73	        "Appended lemmas to /tmp/x/Tutorial.spthy".into()
74	    }
75	    fn static_file(&self, _path: &[String]) -> Option<Vec<u8>> {
76	        None
77	    }
78	    fn load_theory(&self, source: &str) -> Option<Thy> {
79	        // An uploaded theory is born with Upload origin.
80	        source.contains("theory").then(|| Thy {
81	            name: "NSLPK3".into(),
82	            origin: Origin::Uploaded,
83	            lemmas: vec![],
84	        })
85	    }
86	    fn reload(&self, thy: &Thy) -> Thy {
87	        thy.clone()
88	    }
89	    fn apply_method(&self, thy: &Thy, _l: &str, n: usize, _p: &[String]) -> Option<(Thy, Vec<String>)> {
90	        // A proof-derived version keeps the base theory's origin (clone).
91	        (n != 0).then(|| (thy.clone(), vec!["_".to_string()]))
92	    }
93	    fn autoprove(&self, thy: &Thy, _s: &Autoprove) -> (Thy, Vec<String>) {
94	        (thy.clone(), vec!["_".to_string()])
95	    }
96	    fn edit_lemma(&self, thy: &Thy, _n: &str, _t: &str) -> Option<Thy> {
97	        Some(thy.clone())
98	    }
99	    fn add_lemma(&self, thy: &Thy, _p: &str, _t: &str) -> Option<Thy> {
100	        Some(thy.clone())
101	    }
102	    fn delete_lemma(&self, thy: &Thy, name: &str) -> Option<Thy> {
103	        thy.lemmas.iter().any(|l| l == name).then(|| thy.clone())
104	    }
105	    fn lemma_present(&self, thy: &Thy, lemma: &str) -> bool {
106	        thy.lemmas.iter().any(|l| l == lemma)
107	    }
108	    fn del_lemma_path(&self, thy: &Thy, name: &str) -> Option<Thy> {
109	        thy.lemmas.iter().any(|l| l == name).then(|| thy.clone())
110	    }
111	    fn del_proof_step(&self, thy: &Thy, lemma: &str, _p: &[String], _d: bool) -> Option<Thy> {
112	        thy.lemmas.iter().any(|l| l == lemma).then(|| thy.clone())
113	    }
114	    fn apply_diff_method(&self, thy: &Thy, _l: &str, n: usize, _p: &[String]) -> Option<(Thy, Vec<String>)> {
115	        (n != 0).then(|| (thy.clone(), vec!["Rule".to_string()]))
116	    }
117	    fn autoprove_diff(&self, thy: &Thy, _s: &AutoproveDiff) -> (Thy, Vec<String>) {
118	        (thy.clone(), vec!["Rule".to_string()])
119	    }
120	    fn autoprove_all(&self, thy: &Thy, _s: &AutoproveAll) -> Thy {
121	        thy.clone()
122	    }
123	}
124	
125	const RELOAD: &str = "Reload file";
126	const APPEND: &str = "Append modified lemmas to file";
127	
128	// ---------------------------------------------------------------------------
129	// ITEM 1 — origin threaded from meta into the rendered overview shell.
130	// ---------------------------------------------------------------------------
131	
132	#[test]
133	fn local_theory_overview_shows_reload_and_append() {
134	    let mut s = Server::new(Fake, local_base());
